SELECT

FROM project
WHERE deleted = 0

    AND project_name LIKE CONCAT('%', #{projectName}, '%')


    AND customer_id = #{customerId}


    AND status = #{status}


    AND project_type = #{projectType}

ORDER BY created_at DESC

